1	use super::{
2	    observer::{DelegateObserver, Observer},
3	    utils::modulus,
4	};
5	use crate::utils::{move_uninit_slice, slice_as_uninit_mut, slice_assume_init_mut, slice_assume_init_ref};
6	use core::{iter::Chain, mem::MaybeUninit, ptr, slice};
7	#[cfg(feature = "std")]
8	use std::io::{self, Write};
